     1→/** Base error class for SMC Commander */
     2→export class SMCError extends Error {
     3→  constructor(
     4→    message: string,
     5→    public readonly code: string,
     6→  ) {
     7→    super(message);
     8→    this.name = 'SMCError';
     9→  }
    10→}
    11→
    12→/** Thrown when input data fails validation */
    13→export class ValidationError extends SMCError {
    14→  constructor(
    15→    message: string,
    16→    public readonly field: string,
    17→  ) {
    18→    super(message, 'VALIDATION_ERROR');
    19→    this.name = 'ValidationError';
    20→  }
    21→}
    22→
    23→/** Thrown when configuration is invalid */
    24→export class ConfigurationError extends SMCError {
    25→  constructor(
    26→    message: string,
    27→    public readonly configKey: string,
    28→  ) {
    29→    super(message, 'CONFIGURATION_ERROR');
    30→    this.name = 'ConfigurationError';
    31→  }
    32→}
    33→
    34→/** Thrown when analysis encounters an internal error */
    35→export class AnalysisError extends SMCError {
    36→  constructor(
    37→    message: string,
    38→    public readonly module: string,
    39→  ) {
    40→    super(message, 'ANALYSIS_ERROR');
    41→    this.name = 'AnalysisError';
    42→  }
    43→}
