     1→import type {
     2→  Candle,
     3→  SignalResult,
     4→  MacroContext,
     5→  Direction,
     6→  Trend,
     7→  Zone,
     8→  KillZoneName,
     9→  RiskConfig,
    10→  AnalysisConfig,
    11→  LiquidityLevel,
    12→  EntryParams,
    13→  SessionStatus,
    14→} from '../core/types.js';
    15→import { MarketStructure } from '../analysis/MarketStructure.js';
    16→import { LiquidityAnalyzer } from '../analysis/LiquidityAnalyzer.js';
    17→import { EntryDetector } from '../analysis/EntryDetector.js';
    18→import { AMDDetector } from '../analysis/AMDDetector.js';
    19→import { KillZoneManager } from '../analysis/KillZoneManager.js';
    20→import { SetupScorer } from '../scoring/SetupScorer.js';
    21→import { RiskCalculator } from '../scoring/RiskCalculator.js';
    22→import { SessionManager } from './SessionManager.js';
    23→import { validateCandles, buildAnalysisConfig } from '../utils/validation.js';
    24→import * as time from '../utils/time.js';
    25→
    26→/**
    27→ * SMCAnalyzer — Main orchestrator for the SMC trading engine.
    28→ *
    29→ * Runs a 13-step analysis pipeline:
    30→ *  1. Validate inputs
    31→ *  2. Check session status (circuit breaker)
    32→ *  3. Check kill zone
    33→ *  4. Analyze HTF structure and bias
    34→ *  5. Calculate dealing range and zone
    35→ *  6. Map liquidity levels
    36→ *  7. Detect AMD pattern
    37→ *  8. Validate HTF alignment
    38→ *  9. Validate zone alignment
    39→ * 10. Detect entry triggers (FVG/OB)
    40→ * 11. Calculate score
    41→ * 12. Calculate entry parameters
    42→ * 13. Return SignalResult
    43→ */
    44→export class SMCAnalyzer {
    45→  private readonly config: AnalysisConfig;
    46→  private readonly marketStructure: MarketStructure;
    47→  private readonly liquidityAnalyzer: LiquidityAnalyzer;
    48→  private readonly entryDetector: EntryDetector;
    49→  private readonly amdDetector: AMDDetector;
    50→  private readonly killZoneManager: KillZoneManager;
    51→  private readonly setupScorer: SetupScorer;
    52→  private readonly riskCalculator: RiskCalculator;
    53→  private readonly sessionManager: SessionManager;
    54→
    55→  constructor(symbol: string, capital: number, riskConfig?: Partial<RiskConfig>) {
    56→    this.config = buildAnalysisConfig(symbol, capital, riskConfig as RiskConfig | undefined);
    57→    this.marketStructure = new MarketStructure(this.config.swingLookback);
    58→    this.liquidityAnalyzer = new LiquidityAnalyzer();
    59→    this.entryDetector = new EntryDetector(this.config.instrument.minFVGSize);
    60→    this.amdDetector = new AMDDetector();
    61→    this.killZoneManager = new KillZoneManager();
    62→    this.setupScorer = new SetupScorer();
    63→    this.riskCalculator = new RiskCalculator();
    64→    this.sessionManager = new SessionManager(this.config.risk);
    65→  }
    66→
    67→  /**
    68→   * Main analysis pipeline.
    69→   * Takes LTF candle data, HTF candle data, and macro context.
    70→   * Returns a complete SignalResult with tradeability assessment.
    71→   */
    72→  analyze(
    73→    ltfCandles: readonly Candle[],
    74→    htfCandles: readonly Candle[],
    75→    macro: MacroContext,
    76→  ): SignalResult {
    77→    try {
    78→      // Step 1: Validate inputs
    79→      validateCandles(ltfCandles);
    80→      validateCandles(htfCandles);
    81→
    82→      const lastCandle = ltfCandles[ltfCandles.length - 1]!;
    83→      const timestamp = lastCandle.timestamp;
    84→      const currentPrice = lastCandle.close;
    85→
    86→      // Step 2: Check session status
    87→      const sessionStatus = this.sessionManager.checkSessionStatus(timestamp);
    88→      const tradeCheck = this.sessionManager.canTakeNewTrade();
    89→
    90→      if (sessionStatus === 'HALTED' || !tradeCheck.allowed) {
    91→        return this.buildNoTradeResult(
    92→          timestamp,
    93→          currentPrice,
    94→          macro,
    95→          sessionStatus === 'HALTED' ? 'HALTED' : 'ACTIVE',
    96→          [tradeCheck.reason],
    97→        );
    98→      }
    99→
   100→      // Step 3: Check kill zone
   101→      const kzInfo = this.killZoneManager.getCurrentKillZone(timestamp);
   102→      const tradingAllowed = this.killZoneManager.isTradingAllowed(timestamp);
   103→      const killZoneName: KillZoneName = kzInfo?.name ?? 'NONE';
   104→
   105→      if (!tradingAllowed.allowed) {
   106→        return this.buildNoTradeResult(
   107→          timestamp,
   108→          currentPrice,
   109→          macro,
   110→          'NO_TRADE_ZONE',
   111→          [tradingAllowed.reason],
   112→        );
   113→      }
   114→
   115→      // Step 4: Analyze HTF structure
   116→      const htfSwings = this.marketStructure.identifySwingPoints(htfCandles);
   117→      const htfTrend = this.marketStructure.determineTrend(htfSwings);
   118→      // Determine trade direction from HTF bias
   119→      const direction: Direction = htfTrend === 'BULLISH' ? 'LONG' : 'SHORT';
   120→
   121→      // Step 5: Calculate dealing range and zone
   122→      const ltfSwings = this.marketStructure.identifySwingPoints(ltfCandles);
   123→      const dealingRange = this.marketStructure.calculateDealingRange(ltfSwings);
   124→
   125→      let zone: Zone = 'EQUILIBRIUM';
   126→      let zoneValid = false;
   127→      let isInOTE = false;
   128→
   129→      if (dealingRange) {
   130→        zone = this.marketStructure.getZone(currentPrice, dealingRange);
   131→        zoneValid = this.marketStructure.isZoneValid(zone, direction);
   132→        isInOTE = this.marketStructure.isInOTE(currentPrice, dealingRange);
   133→      }
   134→
   135→      // Check HTF alignment
   136→      const htfAligned = this.isHTFAligned(htfTrend, direction);
   137→
   138→      // Step 6: Map liquidity levels
   139→      const liquidityLevels = this.liquidityAnalyzer.mapAllLevels(
   140→        ltfCandles,
   141→        ltfSwings,
   142→        timestamp,
   143→      );
   144→
   145→      // Step 7: Detect sweeps
   146→      const sweeps = this.liquidityAnalyzer.detectSweeps(ltfCandles, liquidityLevels);
   147→      const bestSweep = sweeps.length > 0 ? sweeps[sweeps.length - 1]! : null;
   148→
   149→      // Step 8: Detect AMD pattern
   150→      const asianRange = time.getAsianSessionRange(ltfCandles, timestamp);
   151→      const amd = this.amdDetector.detectAMD(ltfCandles, sweeps, asianRange, liquidityLevels);
   152→
   153→      // Step 9: Detect entry triggers (FVG/OB)
   154→      const fvgs = this.entryDetector.detectFVG(ltfCandles);
   155→      const updatedFVGs = this.entryDetector.updateFVGFillStatus(fvgs, ltfCandles);
   156→      const obs = this.entryDetector.detectOrderBlocks(ltfCandles, ltfSwings);
   157→      const updatedOBs = this.entryDetector.updateOBMitigation(obs, ltfCandles);
   158→
   159→      const bestEntry = this.entryDetector.findBestEntry(updatedFVGs, updatedOBs, direction);
   160→
   161→      // Check FVG-OB overlap
   162→      const hasOverlap = bestEntry.hasOverlap;
   163→
   164→      // Step 10: Calculate score
   165→      const score = this.setupScorer.calculateScore({
   166→        htfTrend,
   167→        htfAligned,
   168→        zone,
   169→        zoneValid,
   170→        direction,
   171→        dealingRange,
   172→        currentPrice,
   173→        sweep: bestSweep,
   174→        amd,
   175→        fvg: bestEntry.fvg,
   176→        ob: bestEntry.ob,
   177→        fvgObOverlap: hasOverlap,
   178→        killZone: killZoneName,
   179→        killZoneQuality: kzInfo?.quality ?? 0,
   180→        macro,
   181→        isInOTE,
   182→      });
   183→
   184→      // Collect disqualifications
   185→      const disqualifications = this.setupScorer.checkDisqualifications({
   186→        htfTrend,
   187→        htfAligned,
   188→        zone,
   189→        zoneValid,
   190→        direction,
   191→        dealingRange,
   192→        currentPrice,
   193→        sweep: bestSweep,
   194→        amd,
   195→        fvg: bestEntry.fvg,
   196→        ob: bestEntry.ob,
   197→        fvgObOverlap: hasOverlap,
   198→        killZone: killZoneName,
   199→        killZoneQuality: kzInfo?.quality ?? 0,
   200→        macro,
   201→        isInOTE,
   202→      });
   203→
   204→      // Step 11: Calculate entry parameters (only if score passes)
   205→      let entry: EntryParams | null = null;
   206→
   207→      if (score.tradeable && disqualifications.length === 0) {
   208→        // Get opposing liquidity targets for TP
   209→        const opposingTargets = this.getOpposingTargets(direction, liquidityLevels);
   210→
   211→        entry = this.riskCalculator.calculateEntryParams(
   212→          direction,
   213→          bestEntry.fvg,
   214→          bestEntry.ob,
   215→          amd,
   216→          opposingTargets,
   217→          dealingRange,
   218→          this.config.instrument,
   219→          this.config.capital,
   220→          this.config.risk.maxRiskPerTrade,
   221→          score.sizing,
   222→          macro.vix.sizingMultiplier,
   223→        );
   224→      }
   225→
   226→      // Step 12: Build final signal result
   227→      const isTradable = entry !== null && score.tradeable && disqualifications.length === 0;
   228→
   229→      return {
   230→        isTradable,
   231→        direction,
   232→        timestamp,
   233→        context: {
   234→          htfBias: htfTrend,
   235→          htfAligned,
   236→          zone,
   237→          zoneValid,
   238→          killZone: killZoneName,
   239→          killZoneActive: kzInfo !== null,
   240→          amd,
   241→          macro,
   242→        },
   243→        liquidity: {
   244→          sweepConfirmed: bestSweep !== null,
   245→          levelSwept: bestSweep?.level ?? null,
   246→          targets: this.getOpposingTargets(direction, liquidityLevels),
   247→        },
   248→        entry,
   249→        score,
   250→        disqualifications,
   251→        sessionStatus: 'ACTIVE',
   252→      };
   253→    } catch (error) {
   254→      // Graceful degradation — never throw from public API
   255→      const msg = error instanceof Error ? error.message : 'Unknown analysis error';
   256→      return this.buildErrorResult(msg);
   257→    }
   258→  }
   259→
   260→  /** Record a trade outcome for session management */
   261→  recordTradeResult(result: 'WIN' | 'LOSS' | 'BE', pnl: number): void {
   262→    this.sessionManager.updateAfterTrade(result, pnl);
   263→  }
   264→
   265→  /** Get current session state */
   266→  getSessionState() {
   267→    return this.sessionManager.getState();
   268→  }
   269→
   270→  /** Reset the session for a new trading day */
   271→  resetSession(date?: string): void {
   272→    this.sessionManager.resetDaily(date);
   273→  }
   274→
   275→  /** Check if HTF trend aligns with trade direction */
   276→  private isHTFAligned(htfTrend: Trend, direction: Direction): boolean {
   277→    if (htfTrend === 'RANGING') return false;
   278→    if (direction === 'LONG' && htfTrend === 'BULLISH') return true;
   279→    if (direction === 'SHORT' && htfTrend === 'BEARISH') return true;
   280→    return false;
   281→  }
   282→
   283→  /** Get opposing liquidity targets for take-profit calculation */
   284→  private getOpposingTargets(
   285→    direction: Direction,
   286→    levels: readonly LiquidityLevel[],
   287→  ): LiquidityLevel[] {
   288→    if (direction === 'LONG') {
   289→      return levels.filter(l =>
   290→        ['BSL', 'EQH', 'PWH', 'PDH', 'ASIAN_HIGH'].includes(l.type) && !l.swept,
   291→      );
   292→    }
   293→    return levels.filter(l =>
   294→      ['SSL', 'EQL', 'PWL', 'PDL', 'ASIAN_LOW'].includes(l.type) && !l.swept,
   295→    );
   296→  }
   297→
   298→  /** Build a no-trade result with reason */
   299→  private buildNoTradeResult(
   300→    timestamp: number,
   301→    _currentPrice: number,
   302→    macro: MacroContext,
   303→    sessionStatus: SessionStatus,
   304→    disqualifications: string[],
   305→  ): SignalResult {
   306→    return {
   307→      isTradable: false,
   308→      direction: 'LONG',
   309→      timestamp,
   310→      context: {
   311→        htfBias: 'RANGING',
   312→        htfAligned: false,
   313→        zone: 'EQUILIBRIUM',
   314→        zoneValid: false,
   315→        killZone: 'NONE',
   316→        killZoneActive: false,
   317→        amd: { phase: 'NONE', confirmed: false },
   318→        macro,
   319→      },
   320→      liquidity: {
   321→        sweepConfirmed: false,
   322→        levelSwept: null,
   323→        targets: [],
   324→      },
   325→      entry: null,
   326→      score: {
   327→        structureAlignment: 0,
   328→        judasSwingQuality: 0,
   329→        entryQuality: 0,
