     1→import type { SessionState, SessionStatus, RiskConfig } from '../core/types.js';
     2→import { DEFAULT_RISK } from '../core/constants.js';
     3→import * as math from '../utils/math.js';
     4→import * as time from '../utils/time.js';
     5→
     6→/**
     7→ * SessionManager — Circuit breaker, daily trade limits, and session state tracking.
     8→ *
     9→ * Halts trading after:
    10→ * - 2 consecutive losses (configurable)
    11→ * - Daily drawdown >= 2% (configurable)
    12→ * - Max trades per day reached
    13→ *
    14→ * Resets automatically at NY midnight.
    15→ */
    16→export class SessionManager {
    17→  private state: SessionState;
    18→  private readonly riskConfig: RiskConfig;
    19→
    20→  constructor(riskConfig?: RiskConfig) {
    21→    this.riskConfig = riskConfig ?? DEFAULT_RISK;
    22→    this.state = this.createFreshState();
    23→  }
    24→
    25→  /** Check if the session allows a new trade */
    26→  checkSessionStatus(timestamp?: number): SessionStatus {
    27→    // Auto-reset if it's a new day
    28→    if (timestamp) {
    29→      const currentDate = time.getSessionDate(timestamp);
    30→      if (currentDate !== this.state.date) {
    31→        this.resetDaily(currentDate);
    32→      }
    33→    }
    34→
    35→    if (this.state.isHalted) return 'HALTED';
    36→
    37→    if (timestamp && !time.isTradingTime(timestamp)) {
    38→      return 'NO_TRADE_ZONE';
    39→    }
    40→
    41→    return 'ACTIVE';
    42→  }
    43→
    44→  /** Record a trade result and update session state */
    45→  updateAfterTrade(result: 'WIN' | 'LOSS' | 'BE', pnl: number): void {
    46→    this.state.tradesCount++;
    47→    this.state.dailyPnL = math.add(this.state.dailyPnL, pnl);
    48→
    49→    if (result === 'LOSS') {
    50→      this.state.consecutiveLosses++;
    51→    } else {
    52→      this.state.consecutiveLosses = 0;
    53→    }
    54→
    55→    // Check circuit breaker conditions
    56→    this.checkCircuitBreaker();
    57→  }
    58→
    59→  /** Reset session state for a new trading day */
    60→  resetDaily(date?: string): void {
    61→    this.state = this.createFreshState(date);
    62→  }
    63→
    64→  /** Check if session is halted */
    65→  isHalted(): boolean {
    66→    return this.state.isHalted;
    67→  }
    68→
    69→  /** Get the halt reason if session is halted */
    70→  getHaltReason(): string | undefined {
    71→    return this.state.haltReason;
    72→  }
    73→
    74→  /** Get a readonly snapshot of session state */
    75→  getState(): Readonly<SessionState> {
    76→    return { ...this.state };
    77→  }
    78→
    79→  /** Check if we can take another trade (under daily limit) */
    80→  canTakeNewTrade(): { allowed: boolean; reason: string } {
    81→    if (this.state.isHalted) {
    82→      return { allowed: false, reason: this.state.haltReason ?? 'Session halted' };
    83→    }
    84→
    85→    if (this.state.tradesCount >= this.riskConfig.maxTradesPerDay) {
    86→      return { allowed: false, reason: `Daily trade limit reached (${this.riskConfig.maxTradesPerDay})` };
    87→    }
    88→
    89→    return { allowed: true, reason: 'Session active' };
    90→  }
    91→
    92→  /** Check circuit breaker conditions and halt if triggered */
    93→  private checkCircuitBreaker(): void {
    94→    // Consecutive losses
    95→    if (this.state.consecutiveLosses >= this.riskConfig.maxConsecutiveLosses) {
    96→      this.state.isHalted = true;
    97→      this.state.haltReason = `Circuit breaker: ${this.state.consecutiveLosses} consecutive losses`;
    98→      return;
    99→    }
   100→
   101→    // Daily trade limit
   102→    if (this.state.tradesCount >= this.riskConfig.maxTradesPerDay) {
   103→      this.state.isHalted = true;
   104→      this.state.haltReason = `Daily trade limit reached (${this.riskConfig.maxTradesPerDay})`;
   105→      return;
   106→    }
   107→
   108→    // Daily drawdown (absolute value check)
   109→    if (this.state.dailyPnL < 0 && Math.abs(this.state.dailyPnL) >= this.riskConfig.maxDailyDrawdown) {
   110→      this.state.isHalted = true;
   111→      this.state.haltReason = `Daily drawdown limit reached (${math.mul(this.riskConfig.maxDailyDrawdown, 100)}%)`;
   112→      return;
   113→    }
   114→  }
   115→
   116→  /** Create a fresh session state */
   117→  private createFreshState(date?: string): SessionState {
   118→    return {
   119→      consecutiveLosses: 0,
   120→      dailyPnL: 0,
   121→      tradesCount: 0,
   122→      isHalted: false,
   123→      haltReason: undefined,
   124→      date: date ?? new Date().toISOString().slice(0, 10),
   125→    };
   126→  }
   127→}
