     1→import type {
     2→  Candle,
     3→  SwingPoint,
     4→  StructureBreak,
     5→  DealingRange,
     6→  Trend,
     7→  Zone,
     8→  Direction,
     9→} from '../core/types.js';
    10→import { OTE_LEVELS } from '../core/constants.js';
    11→import * as math from '../utils/math.js';
    12→
    13→/**
    14→ * MarketStructure — Swing detection, trend analysis, BOS/MSS, dealing ranges.
    15→ * This is the foundational analysis module.
    16→ */
    17→export class MarketStructure {
    18→  private readonly lookback: number;
    19→
    20→  constructor(lookback: number = 5) {
    21→    this.lookback = lookback;
    22→  }
    23→
    24→  /**
    25→   * Detect swing highs and lows using configurable lookback.
    26→   * A swing high: candle[i].high is the highest high in [i-lookback, i+lookback].
    27→   * A swing low: candle[i].low is the lowest low in [i-lookback, i+lookback].
    28→   */
    29→  identifySwingPoints(candles: readonly Candle[]): SwingPoint[] {
    30→    const swings: SwingPoint[] = [];
    31→    if (candles.length < this.lookback * 2 + 1) return swings;
    32→
    33→    for (let i = this.lookback; i < candles.length - this.lookback; i++) {
    34→      const candle = candles[i]!;
    35→      let isSwingHigh = true;
    36→      let isSwingLow = true;
    37→
    38→      for (let j = i - this.lookback; j <= i + this.lookback; j++) {
    39→        if (j === i) continue;
    40→        const compare = candles[j]!;
    41→        if (compare.high >= candle.high) isSwingHigh = false;
    42→        if (compare.low <= candle.low) isSwingLow = false;
    43→        if (!isSwingHigh && !isSwingLow) break;
    44→      }
    45→
    46→      if (isSwingHigh) {
    47→        swings.push({
    48→          timestamp: candle.timestamp,
    49→          price: candle.high,
    50→          index: i,
    51→          type: 'HIGH',
    52→          strength: this.calculateStrength(candles, i, 'HIGH'),
    53→          mitigated: false,
    54→        });
    55→      }
    56→
    57→      if (isSwingLow) {
    58→        swings.push({
    59→          timestamp: candle.timestamp,
    60→          price: candle.low,
    61→          index: i,
    62→          type: 'LOW',
    63→          strength: this.calculateStrength(candles, i, 'LOW'),
    64→          mitigated: false,
    65→        });
    66→      }
    67→    }
    68→
    69→    return swings;
    70→  }
    71→
    72→  /**
    73→   * Determine trend from swing point sequence.
    74→   * BULLISH: Higher Highs + Higher Lows
    75→   * BEARISH: Lower Highs + Lower Lows
    76→   * RANGING: Mixed pattern
    77→   */
    78→  determineTrend(swings: readonly SwingPoint[]): Trend {
    79→    const highs = swings.filter(s => s.type === 'HIGH');
    80→    const lows = swings.filter(s => s.type === 'LOW');
    81→
    82→    if (highs.length < 2 || lows.length < 2) return 'RANGING';
    83→
    84→    const lastHighs = highs.slice(-3);
    85→    const lastLows = lows.slice(-3);
    86→
    87→    let higherHighs = 0;
    88→    let lowerHighs = 0;
    89→    for (let i = 1; i < lastHighs.length; i++) {
    90→      if (math.isGreater(lastHighs[i]!.price, lastHighs[i - 1]!.price)) higherHighs++;
    91→      else if (math.isLess(lastHighs[i]!.price, lastHighs[i - 1]!.price)) lowerHighs++;
    92→    }
    93→
    94→    let higherLows = 0;
    95→    let lowerLows = 0;
    96→    for (let i = 1; i < lastLows.length; i++) {
    97→      if (math.isGreater(lastLows[i]!.price, lastLows[i - 1]!.price)) higherLows++;
    98→      else if (math.isLess(lastLows[i]!.price, lastLows[i - 1]!.price)) lowerLows++;
    99→    }
   100→
   101→    // Majority voting: bullish if most highs are higher AND most lows are higher
   102→    if (higherHighs > lowerHighs && higherLows > lowerLows) {
   103→      return 'BULLISH';
   104→    }
   105→    if (lowerHighs > higherHighs && lowerLows > higherLows) {
   106→      return 'BEARISH';
   107→    }
   108→    return 'RANGING';
   109→  }
   110→
   111→  /**
   112→   * Detect Break of Structure (BOS) — continuation break.
   113→   * In bullish trend: price closes above most recent swing high.
   114→   * In bearish trend: price closes below most recent swing low.
   115→   */
   116→  detectBOS(
   117→    candles: readonly Candle[],
   118→    swings: readonly SwingPoint[],
   119→    trend: Trend,
   120→  ): StructureBreak | null {
   121→    if (trend === 'RANGING') return null;
   122→
   123→    if (trend === 'BULLISH') {
   124→      const highs = swings.filter(s => s.type === 'HIGH');
   125→      const lastHigh = highs[highs.length - 1];
   126→      if (!lastHigh) return null;
   127→
   128→      for (let i = lastHigh.index + 1; i < candles.length; i++) {
   129→        const c = candles[i]!;
   130→        if (math.isGreater(c.close, lastHigh.price)) {
   131→          return {
   132→            type: 'BOS',
   133→            direction: 'LONG',
   134→            level: lastHigh.price,
   135→            index: i,
   136→            timestamp: c.timestamp,
   137→          };
   138→        }
   139→      }
   140→    }
   141→
   142→    if (trend === 'BEARISH') {
   143→      const lows = swings.filter(s => s.type === 'LOW');
   144→      const lastLow = lows[lows.length - 1];
   145→      if (!lastLow) return null;
   146→
   147→      for (let i = lastLow.index + 1; i < candles.length; i++) {
   148→        const c = candles[i]!;
   149→        if (math.isLess(c.close, lastLow.price)) {
   150→          return {
   151→            type: 'BOS',
   152→            direction: 'SHORT',
   153→            level: lastLow.price,
   154→            index: i,
   155→            timestamp: c.timestamp,
   156→          };
   157→        }
   158→      }
   159→    }
   160→
   161→    return null;
   162→  }
   163→
   164→  /**
   165→   * Detect Market Structure Shift (MSS) — reversal break.
   166→   * In bullish trend: price closes below most recent swing low (shift to bearish).
   167→   * In bearish trend: price closes above most recent swing high (shift to bullish).
   168→   */
   169→  detectMSS(
   170→    candles: readonly Candle[],
   171→    swings: readonly SwingPoint[],
   172→    currentTrend: Trend,
   173→  ): { detected: boolean; newDirection: Direction; breakLevel: number; index: number } | null {
   174→    if (currentTrend === 'RANGING') return null;
   175→
   176→    if (currentTrend === 'BULLISH') {
   177→      const lows = swings.filter(s => s.type === 'LOW');
   178→      const lastLow = lows[lows.length - 1];
   179→      if (!lastLow) return null;
   180→
   181→      for (let i = lastLow.index + 1; i < candles.length; i++) {
   182→        const c = candles[i]!;
   183→        if (math.isLess(c.close, lastLow.price)) {
   184→          return {
   185→            detected: true,
   186→            newDirection: 'SHORT',
   187→            breakLevel: lastLow.price,
   188→            index: i,
   189→          };
   190→        }
   191→      }
   192→    }
   193→
   194→    if (currentTrend === 'BEARISH') {
   195→      const highs = swings.filter(s => s.type === 'HIGH');
   196→      const lastHigh = highs[highs.length - 1];
   197→      if (!lastHigh) return null;
   198→
   199→      for (let i = lastHigh.index + 1; i < candles.length; i++) {
   200→        const c = candles[i]!;
   201→        if (math.isGreater(c.close, lastHigh.price)) {
   202→          return {
   203→            detected: true,
   204→            newDirection: 'LONG',
   205→            breakLevel: lastHigh.price,
   206→            index: i,
   207→          };
   208→        }
   209→      }
   210→    }
   211→
   212→    return null;
   213→  }
   214→
   215→  /**
   216→   * Calculate dealing range from most recent significant swing high and low.
   217→   * Includes equilibrium, premium/discount zones, and OTE (62-79% fib).
   218→   */
   219→  calculateDealingRange(swings: readonly SwingPoint[]): DealingRange | null {
   220→    const highs = swings.filter(s => s.type === 'HIGH');
   221→    const lows = swings.filter(s => s.type === 'LOW');
   222→
   223→    if (highs.length === 0 || lows.length === 0) return null;
   224→
   225→    const swingHigh = highs.reduce((a, b) =>
   226→      math.isGreater(a.price, b.price) ? a : b,
   227→    );
   228→    const swingLow = lows.reduce((a, b) =>
   229→      math.isLess(a.price, b.price) ? a : b,
   230→    );
   231→
   232→    const high = swingHigh.price;
   233→    const low = swingLow.price;
   234→    const eq = math.midpoint(high, low);
   235→
   236→    // Premium zone: upper half (above equilibrium)
   237→    // Discount zone: lower half (below equilibrium)
   238→    const premium = { upper: high, lower: eq };
   239→    const discount = { upper: eq, lower: low };
   240→
   241→    // OTE zone: 62% - 79% retracement
   242→    const oteUpper = math.fibLevel(high, low, OTE_LEVELS.lower); // 62% retrace
   243→    const oteLower = math.fibLevel(high, low, OTE_LEVELS.upper); // 79% retrace
   244→
   245→    return {
   246→      high,
   247→      low,
   248→      equilibrium: eq,
   249→      premium,
   250→      discount,
   251→      ote: { upper: oteUpper, lower: oteLower },
   252→    };
   253→  }
   254→
   255→  /**
   256→   * Determine which zone a price falls in relative to the dealing range.
   257→   */
   258→  getZone(price: number, range: DealingRange): Zone {
   259→    if (math.isGte(price, range.premium.lower)) return 'PREMIUM';
   260→    if (math.isLte(price, range.discount.upper)) return 'DISCOUNT';
   261→    return 'EQUILIBRIUM';
   262→  }
   263→
   264→  /**
   265→   * Check if price is in the Optimal Trade Entry zone (62-79% fib retracement).
   266→   */
   267→  isInOTE(price: number, range: DealingRange): boolean {
   268→    return math.isLte(price, range.ote.upper) && math.isGte(price, range.ote.lower);
   269→  }
   270→
   271→  /**
   272→   * Validate zone alignment for direction.
   273→   * Longs should be in discount, shorts in premium.
   274→   */
   275→  isZoneValid(zone: Zone, direction: Direction): boolean {
   276→    if (direction === 'LONG') return zone === 'DISCOUNT';
   277→    if (direction === 'SHORT') return zone === 'PREMIUM';
   278→    return false;
   279→  }
   280→
   281→  /** Calculate swing strength based on surrounding price action (1-5) */
   282→  private calculateStrength(
   283→    candles: readonly Candle[],
   284→    index: number,
   285→    type: 'HIGH' | 'LOW',
   286→  ): number {
   287→    let strength = 1;
   288→    const candle = candles[index]!;
   289→    const extendedLookback = Math.min(this.lookback * 2, index, candles.length - index - 1);
   290→
   291→    // Higher strength if it dominates a wider range
   292→    let dominates = 0;
   293→    for (let j = 1; j <= extendedLookback; j++) {
   294→      const left = candles[index - j];
   295→      const right = candles[index + j];
   296→      if (!left || !right) break;
   297→
   298→      if (type === 'HIGH') {
   299→        if (candle.high > left.high && candle.high > right.high) dominates++;
   300→      } else {
   301→        if (candle.low < left.low && candle.low < right.low) dominates++;
   302→      }
   303→    }
   304→
   305→    strength = Math.min(5, Math.max(1, Math.ceil(dominates / 2)));
   306→    return strength;
   307→  }
   308→}
