    10→/**
    11→ * EntryDetector — FVG and Order Block detection with fill/mitigation tracking.
    12→ */
    13→export class EntryDetector {
    14→  private readonly minFVGSize: number;
    15→
    16→  constructor(minFVGSize: number) {
    17→    this.minFVGSize = minFVGSize;
    18→  }
    19→
    20→  /**
    21→   * Detect Fair Value Gaps in candle data.
    22→   * Bullish FVG: candle[i-1].high < candle[i+1].low (gap up)
    23→   * Bearish FVG: candle[i-1].low > candle[i+1].high (gap down)
    24→   */
    25→  detectFVG(candles: readonly Candle[]): FairValueGap[] {
    26→    const fvgs: FairValueGap[] = [];
    27→    if (candles.length < 3) return fvgs;
    28→
    29→    for (let i = 1; i < candles.length - 1; i++) {
    30→      const prev = candles[i - 1]!;
    31→      const curr = candles[i]!;
    32→      const next = candles[i + 1]!;
    33→
    34→      // Bullish FVG: gap between prev.high and next.low
    35→      if (math.isLess(prev.high, next.low)) {
    36→        const low = prev.high;
    37→        const high = next.low;
    38→        const size = math.sub(high, low);
    39→
    40→        if (math.isGte(size, this.minFVGSize)) {
    41→          fvgs.push({
    42→            high,
    43→            low,
    44→            midpoint: math.midpoint(high, low),
    45→            size,
    46→            direction: 'LONG',
    47→            timestamp: curr.timestamp,
    48→            index: i,
    49→            fillPercent: 0,
    50→            isValid: true,
    51→          });
    52→        }
    53→      }
    54→
    55→      // Bearish FVG: gap between next.high and prev.low
    56→      if (math.isGreater(prev.low, next.high)) {
    57→        const high = prev.low;
    58→        const low = next.high;
    59→        const size = math.sub(high, low);
    60→
    61→        if (math.isGte(size, this.minFVGSize)) {
    62→          fvgs.push({
    63→            high,
    64→            low,
    65→            midpoint: math.midpoint(high, low),
    66→            size,
    67→            direction: 'SHORT',
    68→            timestamp: curr.timestamp,
    69→            index: i,
    70→            fillPercent: 0,
    71→            isValid: true,
    72→          });
    73→        }
    74→      }
    75→    }
    76→
    77→    return fvgs;
    78→  }
    79→
    80→  /**
    81→   * Detect Order Blocks.
    82→   * Bullish OB: last bearish candle before a bullish displacement.
    83→   * Bearish OB: last bullish candle before a bearish displacement.
    84→   */
    85→  detectOrderBlocks(
    86→    candles: readonly Candle[],
    87→    _swings: readonly SwingPoint[],
    88→  ): OrderBlock[] {
    89→    const obs: OrderBlock[] = [];
    90→    if (candles.length < 3) return obs;
    91→
    92→    for (let i = 2; i < candles.length; i++) {
    93→      const curr = candles[i]!;
    94→      const prev = candles[i - 1]!;
    95→
    96→      // Bullish displacement: strong close above previous high
    97→      const isBullishDisplacement =
    98→        math.isGreater(curr.close, curr.open) &&
    99→        math.isGreater(curr.close, prev.high) &&
   100→        math.isGreater(math.sub(curr.close, curr.open), math.mul(math.sub(curr.high, curr.low), 0.5));
   101→
   102→      if (isBullishDisplacement) {
   103→        // Find last bearish candle before this displacement
   104→        for (let j = i - 1; j >= Math.max(0, i - 5); j--) {
   105→          const ob = candles[j]!;
   106→          if (math.isLess(ob.close, ob.open)) {
   107→            // Check if confirmed by price moving past the OB high
   108→            const confirmed = math.isGreater(curr.close, ob.high);
   109→            obs.push({
   110→              high: ob.high,
   111→              low: ob.low,
   112→              open: ob.open,
   113→              close: ob.close,
   114→              timestamp: ob.timestamp,
   115→              index: j,
   116→              direction: 'LONG',
   117→              confirmed,
   118→              mitigated: false,
   119→            });
   120→            break;
   121→          }
   122→        }
   123→      }
   124→
   125→      // Bearish displacement: strong close below previous low
   126→      const isBearishDisplacement =
   127→        math.isLess(curr.close, curr.open) &&
   128→        math.isLess(curr.close, prev.low) &&
   129→        math.isGreater(math.sub(curr.open, curr.close), math.mul(math.sub(curr.high, curr.low), 0.5));
   130→
   131→      if (isBearishDisplacement) {
   132→        // Find last bullish candle before this displacement
   133→        for (let j = i - 1; j >= Math.max(0, i - 5); j--) {
   134→          const ob = candles[j]!;
   135→          if (math.isGreater(ob.close, ob.open)) {
   136→            const confirmed = math.isLess(curr.close, ob.low);
   137→            obs.push({
   138→              high: ob.high,
   139→              low: ob.low,
   140→              open: ob.open,
   141→              close: ob.close,
   142→              timestamp: ob.timestamp,
   143→              index: j,
   144→              direction: 'SHORT',
   145→              confirmed,
   146→              mitigated: false,
   147→            });
   148→            break;
   149→          }
   150→        }
   151→      }
   152→    }
   153→
   154→    return obs;
   155→  }
   156→
   157→  /**
   158→   * Update FVG fill status based on subsequent price action.
   159→   * A bullish FVG fills when price trades down into it.
   160→   * A bearish FVG fills when price trades up into it.
   161→   * Returns new array with updated fill percentages.
   162→   */
   163→  updateFVGFillStatus(
   164→    fvgs: readonly FairValueGap[],
   165→    candles: readonly Candle[],
   166→  ): FairValueGap[] {
   167→    return fvgs.map(fvg => {
   168→      let maxFill = 0;
   169→
   170→      for (let i = fvg.index + 2; i < candles.length; i++) {
   171→        const c = candles[i]!;
   172→
   173→        if (fvg.direction === 'LONG') {
   174→          // Bullish FVG fills from top down
   175→          if (math.isLte(c.low, fvg.high)) {
   176→            const filled = math.sub(fvg.high, math.max(c.low, fvg.low));
   177→            const pct = math.mul(math.div(filled, fvg.size), 100);
   178→            maxFill = Math.max(maxFill, Math.min(100, pct));
   179→          }
   180→        } else {
   181→          // Bearish FVG fills from bottom up
   182→          if (math.isGte(c.high, fvg.low)) {
   183→            const filled = math.sub(math.min(c.high, fvg.high), fvg.low);
   184→            const pct = math.mul(math.div(filled, fvg.size), 100);
   185→            maxFill = Math.max(maxFill, Math.min(100, pct));
   186→          }
   187→        }
   188→      }
   189→
   190→      return {
   191→        ...fvg,
   192→        fillPercent: maxFill,
   193→        isValid: fvg.size >= this.minFVGSize && maxFill < 50,
   194→      };
   195→    });
   196→  }
   197→
   198→  /**
   199→   * Update Order Block mitigation status.
   200→   * Bullish OB is mitigated when price trades through the body midpoint.
   201→   * Bearish OB is mitigated when price trades through the body midpoint.
   202→   */
   203→  updateOBMitigation(
   204→    obs: readonly OrderBlock[],
   205→    candles: readonly Candle[],
   206→  ): OrderBlock[] {
   207→    return obs.map(ob => {
   208→      const bodyMid = math.midpoint(ob.open, ob.close);
   209→
   210→      for (let i = ob.index + 1; i < candles.length; i++) {
   211→        const c = candles[i]!;
   212→        if (ob.direction === 'LONG') {
   213→          // Bullish OB mitigated if price trades below body midpoint
   214→          if (math.isLess(c.low, bodyMid)) {
   215→            return { ...ob, mitigated: true };
   216→          }
   217→        } else {
   218→          // Bearish OB mitigated if price trades above body midpoint
   219→          if (math.isGreater(c.high, bodyMid)) {
   220→            return { ...ob, mitigated: true };
   221→          }
   222→        }
   223→      }
   224→
   225→      return ob;
   226→    });
   227→  }
   228→
   229→  /**
   230→   * Check if a FVG overlaps with an Order Block.
   231→   * This creates a high-confluence entry zone.
   232→   */
   233→  checkFVGOBOverlap(fvg: FairValueGap, ob: OrderBlock): boolean {
   234→    if (fvg.direction !== ob.direction) return false;
   235→    // Overlap: FVG range intersects OB range
   236→    return math.isLte(fvg.low, ob.high) && math.isGte(fvg.high, ob.low);
   237→  }
   238→
   239→  /**
   240→   * Find the best entry zone from available FVGs and OBs.
   241→   * Prioritizes: FVG+OB overlap > valid FVG > confirmed OB
   242→   */
   243→  findBestEntry(
   244→    fvgs: readonly FairValueGap[],
   245→    obs: readonly OrderBlock[],
   246→    direction: Direction,
   247→  ): { fvg: FairValueGap | null; ob: OrderBlock | null; hasOverlap: boolean } {
   248→    const validFVGs = fvgs.filter(f => f.direction === direction && f.isValid);
   249→    const validOBs = obs.filter(o => o.direction === direction && o.confirmed && !o.mitigated);
   250→
   251→    // Check for overlap
   252→    for (const fvg of validFVGs) {
   253→      for (const ob of validOBs) {
   254→        if (this.checkFVGOBOverlap(fvg, ob)) {
   255→          return { fvg, ob, hasOverlap: true };
   256→        }
   257→      }
   258→    }
   259→
   260→    // Return best individual
   261→    const bestFVG = validFVGs[validFVGs.length - 1] ?? null;
   262→    const bestOB = validOBs[validOBs.length - 1] ?? null;
   263→
   264→    return { fvg: bestFVG, ob: bestOB, hasOverlap: false };
   265→  }
   266→}
