     1→import type {
     2→  Candle,
     3→  LiquidityLevel,
     4→  LiquiditySweep,
     5→  AMDPattern,
     6→  Direction,
     7→} from '../core/types.js';
     8→import * as math from '../utils/math.js';
     9→import * as time from '../utils/time.js';
    10→
    11→/**
    12→ * AMDDetector — Power of 3 (Accumulation, Manipulation, Distribution) pattern recognition.
    13→ *
    14→ * Accumulation: Asian session range (18:00-00:00 NY)
    15→ * Manipulation: Judas swing — sweep of Asian range during London/NY open
    16→ * Distribution: Price moves to opposing liquidity after manipulation
    17→ */
    18→export class AMDDetector {
    19→  /**
    20→   * Detect the AMD pattern from candle data and liquidity sweeps.
    21→   */
    22→  detectAMD(
    23→    candles: readonly Candle[],
    24→    sweeps: readonly LiquiditySweep[],
    25→    asianRange: { high: number; low: number } | null,
    26→    liquidityLevels: readonly LiquidityLevel[],
    27→  ): AMDPattern {
    28→    const noPattern: AMDPattern = {
    29→      phase: 'NONE',
    30→      confirmed: false,
    31→    };
    32→
    33→    if (!asianRange || candles.length === 0) return noPattern;
    34→
    35→    // Phase 1: Accumulation — the Asian session range
    36→    const accumulation = {
    37→      high: asianRange.high,
    38→      low: asianRange.low,
    39→    };
    40→
    41→    // Phase 2: Manipulation — look for sweep of Asian range
    42→    const manipulation = this.findManipulation(candles, sweeps, asianRange);
    43→    if (!manipulation) {
    44→      return {
    45→        phase: 'ACCUMULATION',
    46→        accumulationRange: accumulation,
    47→        confirmed: false,
    48→      };
    49→    }
    50→
    51→    // Phase 3: Distribution — calculate target based on direction
    52→    const direction = manipulation.direction;
    53→    const distributionTarget = this.calculateDistributionTarget(
    54→      direction,
    55→      asianRange,
    56→      liquidityLevels,
    57→    );
    58→
    59→    return {
    60→      phase: 'DISTRIBUTION',
    61→      accumulationRange: accumulation,
    62→      manipulationSweep: {
    63→        level: manipulation.sweep.level,
    64→        sweepCandle: manipulation.sweep.sweepCandle,
    65→        penetrationDepth: manipulation.sweep.penetrationDepth,
    66→      },
    67→      distributionTarget,
    68→      confirmed: true,
    69→    };
    70→  }
    71→
    72→  /**
    73→   * Determine which AMD phase we are currently in based on time and pattern state.
    74→   */
    75→  getCurrentPhase(
    76→    timestamp: number,
    77→    asianRange: { high: number; low: number } | null,
    78→    hasManipulation: boolean,
    79→  ): 'ACCUMULATION' | 'MANIPULATION' | 'DISTRIBUTION' | 'NONE' {
    80→    const hour = time.getNYHourDecimal(timestamp);
    81→
    82→    // Asian session: 18:00-00:00 — Accumulation
    83→    if (hour >= 18 || hour < 0) {
    84→      return 'ACCUMULATION';
    85→    }
    86→
    87→    // London/NY open without sweep yet — still looking for Manipulation
    88→    if (!hasManipulation && hour >= 3 && hour < 11) {
    89→      return asianRange ? 'ACCUMULATION' : 'NONE';
    90→    }
    91→
    92→    // After manipulation confirmed — Distribution
    93→    if (hasManipulation) {
    94→      return 'DISTRIBUTION';
    95→    }
    96→
    97→    return 'NONE';
    98→  }
    99→
   100→  /**
   101→   * Find the manipulation (Judas swing) — a sweep of the Asian range
   102→   * during London or NY open kill zones.
   103→   */
   104→  private findManipulation(
   105→    _candles: readonly Candle[],
   106→    sweeps: readonly LiquiditySweep[],
   107→    asianRange: { high: number; low: number },
   108→  ): { sweep: LiquiditySweep; direction: Direction } | null {
   109→    // Look for sweeps of Asian High (bearish manipulation) or Asian Low (bullish manipulation)
   110→    for (const sweep of sweeps) {
   111→      const kz = time.getCurrentKillZone(sweep.sweepCandle.timestamp);
   112→      if (!kz) continue;
   113→
   114→      // Must be during London or NY kill zones
   115→      const isValidTime =
   116→        kz.name === 'LONDON_OPEN' || kz.name === 'NY_OPEN';
   117→      if (!isValidTime) continue;
   118→
   119→      // Sweep of Asian Low = bullish manipulation (fake-out down, real move up)
   120→      if (
   121→        sweep.level.type === 'ASIAN_LOW' ||
   122→        sweep.level.type === 'SSL' ||
   123→        sweep.level.type === 'EQL'
   124→      ) {
   125→        if (math.isLte(sweep.sweepCandle.low, asianRange.low)) {
   126→          return { sweep, direction: 'LONG' };
   127→        }
   128→      }
   129→
   130→      // Sweep of Asian High = bearish manipulation (fake-out up, real move down)
   131→      if (
   132→        sweep.level.type === 'ASIAN_HIGH' ||
   133→        sweep.level.type === 'BSL' ||
   134→        sweep.level.type === 'EQH'
   135→      ) {
   136→        if (math.isGte(sweep.sweepCandle.high, asianRange.high)) {
   137→          return { sweep, direction: 'SHORT' };
   138→        }
   139→      }
   140→    }
   141→
   142→    return null;
   143→  }
   144→
   145→  /**
   146→   * Calculate distribution target — the opposing liquidity level.
   147→   * Bullish: target nearest BSL above (PDH, session high, EQH)
   148→   * Bearish: target nearest SSL below (PDL, session low, EQL)
   149→   */
   150→  private calculateDistributionTarget(
   151→    direction: Direction,
   152→    asianRange: { high: number; low: number },
   153→    levels: readonly LiquidityLevel[],
   154→  ): number | undefined {
   155→    if (direction === 'LONG') {
   156→      // Target: nearest buy-side liquidity above Asian high
   157→      const targets = levels
   158→        .filter(l =>
   159→          ['BSL', 'EQH', 'PWH', 'PDH', 'ASIAN_HIGH'].includes(l.type) &&
   160→          math.isGreater(l.price, asianRange.high) &&
   161→          !l.swept,
   162→        )
   163→        .sort((a, b) => a.price - b.price);
   164→
   165→      return targets[0]?.price;
   166→    }
   167→
   168→    if (direction === 'SHORT') {
   169→      // Target: nearest sell-side liquidity below Asian low
   170→      const targets = levels
   171→        .filter(l =>
   172→          ['SSL', 'EQL', 'PWL', 'PDL', 'ASIAN_LOW'].includes(l.type) &&
   173→          math.isLess(l.price, asianRange.low) &&
   174→          !l.swept,
   175→        )
   176→        .sort((a, b) => b.price - a.price);
   177→
   178→      return targets[0]?.price;
   179→    }
   180→
   181→    return undefined;
   182→  }
