     1→import type {
     2→  Trend,
     3→  Zone,
     4→  Direction,
     5→  SetupScore,
     6→  ScoreGrade,
     7→  AMDPattern,
     8→  LiquiditySweep,
     9→  FairValueGap,
    10→  OrderBlock,
    11→  DealingRange,
    12→  MacroContext,
    13→  KillZoneName,
    14→} from '../core/types.js';
    15→import {
    16→  IMMUTABLE_RULES,
    17→  SCORE_GRADES,
    18→  SCORE_MAXIMUMS,
    19→} from '../core/constants.js';
    20→import * as math from '../utils/math.js';
    21→
    22→interface ScoreInput {
    23→  readonly htfTrend: Trend;
    24→  readonly htfAligned: boolean;
    25→  readonly zone: Zone;
    26→  readonly zoneValid: boolean;
    27→  readonly direction: Direction;
    28→  readonly dealingRange: DealingRange | null;
    29→  readonly currentPrice: number;
    30→  readonly sweep: LiquiditySweep | null;
    31→  readonly amd: AMDPattern;
    32→  readonly fvg: FairValueGap | null;
    33→  readonly ob: OrderBlock | null;
    34→  readonly fvgObOverlap: boolean;
    35→  readonly killZone: KillZoneName;
    36→  readonly killZoneQuality: number;
    37→  readonly macro: MacroContext;
    38→  readonly isInOTE: boolean;
    39→}
    40→
    41→/**
    42→ * SetupScorer — 100-point scoring system for trade setup quality.
    43→ *
    44→ * Categories:
    45→ *   A. Structure Alignment: 30 pts max
    46→ *   B. Judas Swing Quality: 25 pts max
    47→ *   C. Entry Quality: 25 pts max
    48→ *   D. Macro Context: 20 pts max
    49→ */
    50→export class SetupScorer {
    51→  /**
    52→   * Calculate the complete setup score.
    53→   * Returns score breakdown, grade, sizing recommendation, and tradeability.
    54→   */
    55→  calculateScore(input: ScoreInput): SetupScore {
    56→    // Check disqualifications first
    57→    const disqualifications = this.checkDisqualifications(input);
    58→
    59→    if (disqualifications.length > 0) {
    60→      return {
    61→        structureAlignment: 0,
    62→        judasSwingQuality: 0,
    63→        entryQuality: 0,
    64→        macroContext: 0,
    65→        total: 0,
    66→        grade: 'DISQUALIFIED',
    67→        sizing: 0,
    68→        tradeable: false,
    69→      };
    70→    }
    71→
    72→    const structureAlignment = this.scoreStructure(input);
    73→    const judasSwingQuality = this.scoreJudasSwing(input);
    74→    const entryQuality = this.scoreEntry(input);
    75→    const macroContext = this.scoreMacro(input);
    76→
    77→    const total = structureAlignment + judasSwingQuality + entryQuality + macroContext;
    78→    const grade = this.assignGrade(total);
    79→    const sizing = this.getSizing(grade);
    80→    const tradeable = total >= IMMUTABLE_RULES.MIN_SCORE_THRESHOLD && grade !== 'DISQUALIFIED';
    81→
    82→    return {
    83→      structureAlignment,
    84→      judasSwingQuality,
    85→      entryQuality,
    86→      macroContext,
    87→      total,
    88→      grade,
    89→      sizing,
    90→      tradeable,
    91→    };
    92→  }
    93→
    94→  /** Check for hard disqualification conditions */
    95→  checkDisqualifications(input: ScoreInput): string[] {
    96→    const dqs: string[] = [];
    97→
    98→    if (IMMUTABLE_RULES.HTF_ALIGNMENT_REQUIRED && !input.htfAligned) {
    99→      dqs.push('HTF bias not aligned');
   100→    }
   101→
   102→    if (IMMUTABLE_RULES.LONG_ONLY_IN_DISCOUNT && input.direction === 'LONG' && input.zone !== 'DISCOUNT') {
   103→      dqs.push('Long entry not in discount zone');
   104→    }
   105→
   106→    if (IMMUTABLE_RULES.SHORT_ONLY_IN_PREMIUM && input.direction === 'SHORT' && input.zone !== 'PREMIUM') {
   107→      dqs.push('Short entry not in premium zone');
   108→    }
   109→
   110→    if (IMMUTABLE_RULES.LIQUIDITY_SWEEP_REQUIRED && !input.sweep) {
   111→      dqs.push('No liquidity sweep confirmed');
   112→    }
   113→
   114→    if (input.macro.vix.interpretation === 'PANIC') {
   115→      dqs.push('VIX in PANIC territory');
   116→    }
   117→
   118→    if (IMMUTABLE_RULES.KILL_ZONE_REQUIRED && input.killZone === 'NONE') {
   119→      dqs.push('Outside kill zone');
   120→    }
   121→
   122→    if (input.macro.newsFilter.noTradeWindow) {
   123→      dqs.push('High impact news window');
   124→    }
   125→
   126→    return dqs;
   127→  }
   128→
   129→  /**
   130→   * Structure Alignment score (max 30 pts).
   131→   * - D1 trend aligned with direction: +10
   132→   * - Zone correct for direction: +10
   133→   * - Price in OTE zone: +10
   134→   */
   135→  private scoreStructure(input: ScoreInput): number {
   136→    let score = 0;
   137→
   138→    // HTF trend alignment (+10)
   139→    if (input.htfAligned) score += 10;
   140→
   141→    // Correct zone for direction (+10)
   142→    if (input.zoneValid) score += 10;
   143→
   144→    // Price in OTE zone (+10)
   145→    if (input.isInOTE) score += 10;
   146→
   147→    return Math.min(score, SCORE_MAXIMUMS.structureAlignment);
   148→  }
   149→
   150→  /**
   151→   * Judas Swing Quality score (max 25 pts).
   152→   * - Level rank S+/S swept: +15, A+/A: +10, B+/B: +5
   153→   * - AMD confirmed: +5
   154→   * - Fast reintegration (<5 candles): +5
   155→   */
   156→  private scoreJudasSwing(input: ScoreInput): number {
   157→    let score = 0;
   158→
   159→    if (input.sweep) {
   160→      // Rank-based score
   161→      const rank = input.sweep.level.rank;
   162→      if (rank === 'S+' || rank === 'S') score += 15;
   163→      else if (rank === 'A+' || rank === 'A') score += 10;
   164→      else if (rank === 'B+' || rank === 'B') score += 5;
   165→
   166→      // Fast reintegration bonus
   167→      if (input.sweep.reintegrated && input.sweep.reintegrationSpeed <= 5) {
   168→        score += 5;
   169→      }
   170→    }
   171→
   172→    // AMD confirmed
   173→    if (input.amd.confirmed) score += 5;
   174→
   175→    return Math.min(score, SCORE_MAXIMUMS.judasSwingQuality);
   176→  }
   177→
   178→  /**
   179→   * Entry Quality score (max 25 pts).
   180→   * - FVG in OTE zone: +10
   181→   * - FVG size >= 10 pts: +5
   182→   * - FVG overlaps OB: +5
   183→   * - Valid Order Block: +5
   184→   */
   185→  private scoreEntry(input: ScoreInput): number {
   186→    let score = 0;
   187→
   188→    if (input.fvg && input.fvg.isValid) {
   189→      // FVG in OTE zone
   190→      if (input.isInOTE) score += 10;
   191→      else score += 5;
   192→
   193→      // FVG size bonus
   194→      if (math.isGte(input.fvg.size, 10)) score += 5;
   195→    }
   196→
   197→    // FVG + OB overlap
   198→    if (input.fvgObOverlap) score += 5;
   199→
   200→    // Valid OB
   201→    if (input.ob && input.ob.confirmed && !input.ob.mitigated) {
   202→      score += 5;
   203→    }
   204→
   205→    return Math.min(score, SCORE_MAXIMUMS.entryQuality);
   206→  }
   207→
   208→  /**
   209→   * Macro Context score (max 20 pts).
   210→   * - No high impact news: +5
   211→   * - VIX < 20 (calm/normal): +5
   212→   * - DXY confirms direction: +5
   213→   * - Sentiment contrarian signal: +5
   214→   */
   215→  private scoreMacro(input: ScoreInput): number {
   216→    let score = 0;
   217→
   218→    // No high impact news
   219→    if (!input.macro.newsFilter.highImpactToday) score += 5;
   220→
   221→    // VIX calm/normal
   222→    if (input.macro.vix.level < 20) score += 5;
   223→
   224→    // DXY confirmation
   225→    const dxyDir = input.macro.dxy.implication;
   226→    if (dxyDir !== 'NEUTRAL' && dxyDir === input.direction) score += 5;
   227→
   228→    // Sentiment contrarian
   229→    if (input.macro.sentiment) {
   230→      if (input.macro.sentiment.contrarianSignal === input.direction) score += 5;
   231→    }
   232→
   233→    return Math.min(score, SCORE_MAXIMUMS.macroContext);
   234→  }
   235→
   236→  /** Map total score to grade */
   237→  private assignGrade(total: number): ScoreGrade {
   238→    if (total >= SCORE_GRADES['A+'].min) return 'A+';
   239→    if (total >= SCORE_GRADES['A'].min) return 'A';
   240→    if (total >= SCORE_GRADES['B+'].min) return 'B+';
   241→    if (total >= SCORE_GRADES['B'].min) return 'B';
   242→    return 'C';
   243→  }
   244→
   245→  /** Get position sizing multiplier for grade */
   246→  private getSizing(grade: ScoreGrade): number {
   247→    return SCORE_GRADES[grade]?.sizing ?? 0;
   248→  }
   249→}
