     1→import type {
     2→  Direction,
     3→  EntryParams,
     4→  EntryType,
     5→  FairValueGap,
     6→  OrderBlock,
     7→  LiquidityLevel,
     8→  InstrumentConfig,
     9→  DealingRange,
    10→  AMDPattern,
    11→} from '../core/types.js';
    12→import * as math from '../utils/math.js';
    13→
    14→/**
    15→ * RiskCalculator — Position sizing, stop loss, and take profit calculation.
    16→ * Enforces maximum SL distance and minimum R:R ratio.
    17→ */
    18→export class RiskCalculator {
    19→  /**
    20→   * Calculate complete entry parameters for a trade signal.
    21→   *
    22→   * @param direction Trade direction
    23→   * @param fvg Best FVG for entry (if available)
    24→   * @param ob Best Order Block for entry (if available)
    25→   * @param amd AMD pattern (for SL placement)
    26→   * @param targets Opposing liquidity levels for TP
    27→   * @param range Dealing range
    28→   * @param instrument Instrument configuration
    29→   * @param capital Account capital
    30→   * @param riskPercent Risk per trade (e.g., 0.01 for 1%)
    31→   * @param sizingMultiplier Score-based sizing (0-1)
    32→   * @param vixMultiplier VIX-based sizing (0-1)
    33→   */
    34→  calculateEntryParams(
    35→    direction: Direction,
    36→    fvg: FairValueGap | null,
    37→    ob: OrderBlock | null,
    38→    amd: AMDPattern,
    39→    targets: readonly LiquidityLevel[],
    40→    range: DealingRange | null,
    41→    instrument: InstrumentConfig,
    42→    capital: number,
    43→    riskPercent: number,
    44→    sizingMultiplier: number,
    45→    vixMultiplier: number,
    46→  ): EntryParams | null {
    47→    // Determine entry type and price
    48→    const { entryType, entryPrice } = this.determineEntry(direction, fvg, ob);
    49→    if (entryPrice === null) return null;
    50→
    51→    // Calculate stop loss
    52→    const stopLoss = this.calculateStopLoss(
    53→      direction,
    54→      amd,
    55→      fvg,
    56→      ob,
    57→      range,
    58→      instrument.spread,
    59→    );
    60→
    61→    const slDistance = math.pointsDistance(entryPrice, stopLoss);
    62→
    63→    // Validate SL distance
    64→    if (math.isGreater(slDistance, instrument.maxSLPoints)) {
    65→      return null; // SL too wide
    66→    }
    67→
    68→    if (slDistance === 0) return null;
    69→
    70→    // Calculate take profits
    71→    const { tp1, tp2, tp3 } = this.calculateTakeProfits(
    72→      direction,
    73→      entryPrice,
    74→      slDistance,
    75→      targets,
    76→    );
    77→
    78→    // Calculate R:R (using TP1 as minimum)
    79→    const rr = math.div(math.pointsDistance(entryPrice, tp1), slDistance);
    80→    if (math.isLess(rr, 2)) return null; // Minimum 2R
    81→
    82→    // Calculate position size
    83→    const effectiveRisk = math.mul(riskPercent, math.mul(sizingMultiplier, vixMultiplier));
    84→    const riskAmount = math.mul(capital, effectiveRisk);
    85→    const positionSize = this.calculatePositionSize(
    86→      riskAmount,
    87→      slDistance,
    88→      instrument.pointValue,
    89→    );
    90→
    91→    if (positionSize <= 0) return null;
    92→
    93→    return {
    94→      type: entryType,
    95→      price: entryPrice,
    96→      stopLoss,
    97→      slDistance,
    98→      tp1,
    99→      tp2,
   100→      tp3,
   101→      riskReward: math.roundTo(rr, 2),
   102→      positionSize,
   103→      riskAmount: math.roundTo(riskAmount, 2),
   104→      riskPercent: math.roundTo(math.mul(effectiveRisk, 100), 2),
   105→    };
   106→  }
   107→
   108→  /**
   109→   * Calculate position size.
   110→   * positionSize = riskAmount / (slDistance * pointValue)
   111→   */
   112→  calculatePositionSize(
   113→    riskAmount: number,
   114→    slDistance: number,
   115→    pointValue: number,
   116→  ): number {
   117→    const denominator = math.mul(slDistance, pointValue);
   118→    if (denominator === 0) return 0;
   119→    return Math.floor(math.div(riskAmount, denominator));
   120→  }
   121→
   122→  /**
   123→   * Calculate stop loss placement.
   124→   * For longs: below the Judas sweep low / OB low + spread buffer.
   125→   * For shorts: above the Judas sweep high / OB high + spread buffer.
   126→   */
   127→  calculateStopLoss(
   128→    direction: Direction,
   129→    amd: AMDPattern,
   130→    fvg: FairValueGap | null,
   131→    ob: OrderBlock | null,
   132→    range: DealingRange | null,
   133→    spread: number,
   134→  ): number {
   135→    if (direction === 'LONG') {
   136→      // SL below the lowest relevant level
   137→      const candidates: number[] = [];
   138→
   139→      if (amd.manipulationSweep) {
   140→        candidates.push(amd.manipulationSweep.sweepCandle.low);
   141→      }
   142→      if (ob) {
   143→        candidates.push(ob.low);
   144→      }
   145→      if (fvg) {
   146→        candidates.push(fvg.low);
   147→      }
   148→      if (range) {
   149→        candidates.push(range.discount.lower);
   150→      }
   151→
   152→      if (candidates.length === 0) return 0;
   153→
   154→      const lowest = Math.min(...candidates);
   155→      return math.sub(lowest, spread);
   156→    }
   157→
   158→    // SHORT
   159→    const candidates: number[] = [];
   160→
   161→    if (amd.manipulationSweep) {
   162→      candidates.push(amd.manipulationSweep.sweepCandle.high);
   163→    }
   164→    if (ob) {
   165→      candidates.push(ob.high);
   166→    }
   167→    if (fvg) {
   168→      candidates.push(fvg.high);
   169→    }
   170→    if (range) {
   171→      candidates.push(range.premium.upper);
   172→    }
   173→
   174→    if (candidates.length === 0) return 0;
   175→
   176→    const highest = Math.max(...candidates);
   177→    return math.add(highest, spread);
   178→  }
   179→
   180→  /**
   181→   * Calculate three take-profit levels.
   182→   * TP1: Nearest opposing liquidity or 2R (50% exit)
   183→   * TP2: Second target or 3R (30% exit)
   184→   * TP3: PWH/PWL or AMD distribution target or 4R (20% exit, trailing)
   185→   */
   186→  calculateTakeProfits(
   187→    direction: Direction,
   188→    entryPrice: number,
   189→    slDistance: number,
   190→    targets: readonly LiquidityLevel[],
   191→  ): { tp1: number; tp2: number; tp3: number } {
   192→    const sortedTargets = [...targets]
   193→      .filter(t => {
   194→        if (direction === 'LONG') {
   195→          return ['BSL', 'EQH', 'PWH', 'PDH', 'ASIAN_HIGH'].includes(t.type) &&
   196→            math.isGreater(t.price, entryPrice);
   197→        }
   198→        return ['SSL', 'EQL', 'PWL', 'PDL', 'ASIAN_LOW'].includes(t.type) &&
   199→          math.isLess(t.price, entryPrice);
   200→      })
   201→      .sort((a, b) => {
   202→        const distA = math.pointsDistance(a.price, entryPrice);
   203→        const distB = math.pointsDistance(b.price, entryPrice);
   204→        return distA - distB;
   205→      });
   206→
   207→    // Default R-multiples
   208→    const defaultTP1 = direction === 'LONG'
   209→      ? math.add(entryPrice, math.mul(slDistance, 2))
   210→      : math.sub(entryPrice, math.mul(slDistance, 2));
   211→
   212→    const defaultTP2 = direction === 'LONG'
   213→      ? math.add(entryPrice, math.mul(slDistance, 3))
   214→      : math.sub(entryPrice, math.mul(slDistance, 3));
   215→
   216→    const defaultTP3 = direction === 'LONG'
   217→      ? math.add(entryPrice, math.mul(slDistance, 4))
   218→      : math.sub(entryPrice, math.mul(slDistance, 4));
   219→
   220→    // Use liquidity targets if available, fallback to R-multiples
   221→    const tp1 = sortedTargets[0]?.price ?? defaultTP1;
   222→    const tp2 = sortedTargets[1]?.price ?? defaultTP2;
   223→    const tp3 = sortedTargets[2]?.price ?? defaultTP3;
   224→
   225→    return { tp1, tp2, tp3 };
   226→  }
   227→
   228→  /** Determine entry type and price from available zones */
   229→  private determineEntry(
   230→    direction: Direction,
   231→    fvg: FairValueGap | null,
   232→    ob: OrderBlock | null,
   233→  ): { entryType: EntryType; entryPrice: number | null } {
   234→    // FVG + OB overlap: enter at FVG midpoint
   235→    if (fvg && ob && fvg.isValid) {
   236→      return { entryType: 'FVG', entryPrice: fvg.midpoint };
   237→    }
   238→
   239→    // FVG only: enter at midpoint
   240→    if (fvg && fvg.isValid) {
   241→      return { entryType: 'FVG', entryPrice: fvg.midpoint };
   242→    }
   243→
   244→    // OB only: enter at OB boundary
   245→    if (ob && ob.confirmed && !ob.mitigated) {
   246→      const price = direction === 'LONG'
   247→        ? ob.high // Enter at OB high for longs (price coming back up into OB)
   248→        : ob.low;  // Enter at OB low for shorts
   249→      return { entryType: 'ORDER_BLOCK', entryPrice: price };
   250→    }
   251→
   252→    return { entryType: 'FVG', entryPrice: null };
   253→  }
   254→}
