    13→  return new Decimal(a).minus(b).toNumber();
    14→}
    15→
    16→/** Multiply two numbers with decimal precision */
    17→export function mul(a: number, b: number): number {
    18→  return new Decimal(a).times(b).toNumber();
    19→}
    20→
    21→/** Divide a by b with decimal precision */
    22→export function div(a: number, b: number): number {
    23→  if (b === 0) return 0;
    24→  return new Decimal(a).dividedBy(b).toNumber();
    25→}
    26→
    27→/** Absolute value */
    28→export function abs(a: number): number {
