    36→
    37→/** Calculate percentage change from a to b */
    38→export function percentChange(from: number, to: number): number {
    39→  if (from === 0) return 0;
    40→  return new Decimal(to).minus(from).dividedBy(new Decimal(from).abs()).times(100).toNumber();
    41→}
    42→
    43→/** Calculate fibonacci retracement level: high - (high - low) * ratio */
    44→export function fibLevel(high: number, low: number, ratio: number): number {
    45→  const range = new Decimal(high).minus(low);
    46→  return new Decimal(high).minus(range.times(ratio)).toNumber();
    47→}
    48→
    49→/** Calculate distance in points between two prices */
    50→export function pointsDistance(a: number, b: number): number {
    51→  return new Decimal(a).minus(b).abs().toNumber();
