    57→ */
    58→export function isApproxEqual(a: number, b: number, tolerance: number): boolean {
    59→  return new Decimal(a).minus(b).abs().lte(tolerance);
    60→}
    61→
    62→/** Check if a > b with decimal precision */
    63→export function isGreater(a: number, b: number): boolean {
    64→  return new Decimal(a).greaterThan(b);
    65→}
    66→
    67→/** Check if a < b with decimal precision */
    68→export function isLess(a: number, b: number): boolean {
