    75→}
    76→
    77→/** Check if a <= b with decimal precision */
    78→export function isLte(a: number, b: number): boolean {
    79→  return new Decimal(a).lessThanOrEqualTo(b);
    80→}
    81→
    82→/** Round to a specific number of decimal places */
    83→export function roundTo(value: number, decimals: number): number {
    84→  return new Decimal(value).toDecimalPlaces(decimals).toNumber();
