    86→
    87→/**
    88→ * Calculate Average True Range over a period.
    89→ * TR = max(H-L, |H-prevC|, |L-prevC|)
    90→ */
    91→export function atr(candles: readonly Candle[], period: number): number {
    92→  if (candles.length < 2) return 0;
    93→  const effectivePeriod = Math.min(period, candles.length - 1);
    94→  let sum = new Decimal(0);
    95→
    96→  for (let i = candles.length - effectivePeriod; i < candles.length; i++) {
    97→    const candle = candles[i]!;
    98→    const prev = candles[i - 1]!;
    99→    const hl = new Decimal(candle.high).minus(candle.low);
   100→    const hpc = new Decimal(candle.high).minus(prev.close).abs();
   101→    const lpc = new Decimal(candle.low).minus(prev.close).abs();
   102→    sum = sum.plus(Decimal.max(hl, hpc, lpc));
   103→  }
   104→
   105→  return sum.dividedBy(effectivePeriod).toNumber();
   106→}
