     1→import { toZonedTime } from 'date-fns-tz';
     2→import { KILL_ZONES, NO_TRADE_ZONES } from '../core/constants.js';
     3→import type { KillZoneName, KillZoneConfig, Candle } from '../core/types.js';
     4→
     5→const NY_TIMEZONE = 'America/New_York';
     6→
     7→/** Convert a Unix timestamp (ms) to a Date in NY timezone */
     8→export function toNYTime(timestamp: number): Date {
     9→  return toZonedTime(new Date(timestamp), NY_TIMEZONE);
    10→}
    11→
    12→/** Get NY hour as decimal (e.g., 9:30 = 9.5) */
    13→export function getNYHourDecimal(timestamp: number): number {
    14→  const ny = toNYTime(timestamp);
    15→  return ny.getHours() + ny.getMinutes() / 60;
    16→}
    17→
    18→/** Get NY day of week (0=Sun, 6=Sat) */
    19→export function getNYDayOfWeek(timestamp: number): number {
    20→  return toNYTime(timestamp).getDay();
    21→}
    22→
    23→/** Check if a timestamp falls on a weekend */
    24→export function isWeekend(timestamp: number): boolean {
    25→  const day = getNYDayOfWeek(timestamp);
    26→  return day === 0 || day === 6;
    27→}
    28→
    29→/**
    30→ * Check if a timestamp falls within a kill zone.
    31→ * Handles midnight-crossing zones (e.g., Asian: 18:00-00:00).
    32→ */
    33→function isInTimeRange(hour: number, start: number, end: number): boolean {
    34→  if (start > end) {
    35→    // Crosses midnight: e.g., 18:00 to 00:00
    36→    return hour >= start || hour < end;
    37→  }
    38→  return hour >= start && hour < end;
    39→}
    40→
    41→/** Get the current kill zone for a timestamp, or null if outside all zones */
    42→export function getCurrentKillZone(timestamp: number): {
    43→  name: KillZoneName;
    44→  quality: number;
    45→  allowed: boolean;
    46→  config: KillZoneConfig;
    47→} | null {
    48→  const hour = getNYHourDecimal(timestamp);
    49→
    50→  for (const kz of KILL_ZONES) {
    51→    if (isInTimeRange(hour, kz.start, kz.end)) {
    52→      return { name: kz.name, quality: kz.quality, allowed: kz.allowed, config: kz };
    53→    }
    54→  }
    55→  return null;
    56→}
    57→
    58→/** Check if the timestamp is in a no-trade zone */
    59→export function isNoTradeZone(timestamp: number): boolean {
    60→  const hour = getNYHourDecimal(timestamp);
    61→  return NO_TRADE_ZONES.some(ntz => hour >= ntz.start && hour < ntz.end);
    62→}
    63→
    64→/** Check if trading is allowed at this time */
    65→export function isTradingTime(timestamp: number): boolean {
    66→  if (isWeekend(timestamp)) return false;
    67→  if (isNoTradeZone(timestamp)) return false;
    68→  return getCurrentKillZone(timestamp) !== null;
    69→}
    70→
    71→/** Get NY date string "YYYY-MM-DD" for session grouping */
    72→export function getSessionDate(timestamp: number): string {
    73→  const ny = toNYTime(timestamp);
    74→  const y = ny.getFullYear();
    75→  const m = String(ny.getMonth() + 1).padStart(2, '0');
    76→  const d = String(ny.getDate()).padStart(2, '0');
    77→  return `${y}-${m}-${d}`;
    78→}
    79→
    80→/**
    81→ * Filter candles to Asian session (18:00-00:00 NY).
    82→ * Returns the high and low of the Asian range.
    83→ */
    84→export function getAsianSessionRange(
    85→  candles: readonly Candle[],
    86→  _referenceTimestamp: number,
    87→): { high: number; low: number } | null {
    88→  const asianCandles = candles.filter(c => {
    89→    const hour = getNYHourDecimal(c.timestamp);
    90→    // Asian session: 18:00 to 00:00 NY time
    91→    // Only include candles from the same or previous session date
    92→    return hour >= 18 || hour < 0;
    93→  });
    94→
    95→  if (asianCandles.length === 0) return null;
    96→
    97→  let high = -Infinity;
    98→  let low = Infinity;
    99→  for (const c of asianCandles) {
   100→    if (c.high > high) high = c.high;
   101→    if (c.low < low) low = c.low;
   102→  }
   103→
   104→  if (high === -Infinity || low === Infinity) return null;
   105→  return { high, low };
   106→}
   107→
   108→/**
   109→ * Get previous day's high and low from candle data.
   110→ * Looks for candles from the trading day before the reference timestamp.
   111→ */
   112→export function getPreviousDayRange(
   113→  candles: readonly Candle[],
   114→  referenceTimestamp: number,
   115→): { high: number; low: number } | null {
   116→  const refDate = getSessionDate(referenceTimestamp);
   117→  const prevDayCandles = candles.filter(c => {
   118→    const candleDate = getSessionDate(c.timestamp);
   119→    return candleDate < refDate;
   120→  });
   121→
   122→  if (prevDayCandles.length === 0) return null;
   123→
   124→  // Get the most recent previous day
   125→  const lastDate = getSessionDate(prevDayCandles[prevDayCandles.length - 1]!.timestamp);
   126→  const dayCandles = prevDayCandles.filter(c => getSessionDate(c.timestamp) === lastDate);
   127→
   128→  let high = -Infinity;
   129→  let low = Infinity;
   130→  for (const c of dayCandles) {
   131→    if (c.high > high) high = c.high;
   132→    if (c.low < low) low = c.low;
   133→  }
   134→
   135→  if (high === -Infinity || low === Infinity) return null;
   136→  return { high, low };
   137→}
   138→
   139→/**
   140→ * Get previous week's high and low from candle data.
   141→ */
   142→export function getPreviousWeekRange(
   143→  candles: readonly Candle[],
   144→  referenceTimestamp: number,
   145→): { high: number; low: number } | null {
   146→  const refNY = toNYTime(referenceTimestamp);
   147→  const currentWeekStart = new Date(refNY);
   148→  currentWeekStart.setDate(refNY.getDate() - refNY.getDay());
   149→  currentWeekStart.setHours(0, 0, 0, 0);
   150→
   151→  const prevWeekEnd = currentWeekStart.getTime();
   152→  const prevWeekStart = prevWeekEnd - 7 * 24 * 60 * 60 * 1000;
   153→
   154→  const weekCandles = candles.filter(c => {
   155→    const t = c.timestamp;
   156→    return t >= prevWeekStart && t < prevWeekEnd;
   157→  });
   158→
   159→  if (weekCandles.length === 0) return null;
   160→
   161→  let high = -Infinity;
   162→  let low = Infinity;
   163→  for (const c of weekCandles) {
   164→    if (c.high > high) high = c.high;
   165→    if (c.low < low) low = c.low;
   166→  }
   167→
   168→  if (high === -Infinity || low === Infinity) return null;
   169→  return { high, low };
   170→}
