     1→import { ValidationError, ConfigurationError } from '../core/errors.js';
     2→import { INSTRUMENTS, DEFAULT_RISK } from '../core/constants.js';
     3→import type { Candle, InstrumentConfig, RiskConfig, AnalysisConfig } from '../core/types.js';
     4→
     5→/**
     6→ * Validate an array of candles for correctness.
     7→ * Checks OHLC relationships, ascending timestamps, and valid values.
     8→ */
     9→export function validateCandles(candles: readonly Candle[]): void {
    10→  if (!Array.isArray(candles) || candles.length === 0) {
    11→    throw new ValidationError('Candles array must be non-empty', 'candles');
    12→  }
    13→
    14→  for (let i = 0; i < candles.length; i++) {
    15→    const c = candles[i]!;
    16→
    17→    if (typeof c.timestamp !== 'number' || !isFinite(c.timestamp) || c.timestamp <= 0) {
    18→      throw new ValidationError(`Invalid timestamp at index ${i}`, 'candles.timestamp');
    19→    }
    20→    if (typeof c.open !== 'number' || !isFinite(c.open) || c.open <= 0) {
    21→      throw new ValidationError(`Invalid open at index ${i}`, 'candles.open');
    22→    }
    23→    if (typeof c.high !== 'number' || !isFinite(c.high) || c.high <= 0) {
    24→      throw new ValidationError(`Invalid high at index ${i}`, 'candles.high');
    25→    }
    26→    if (typeof c.low !== 'number' || !isFinite(c.low) || c.low <= 0) {
    27→      throw new ValidationError(`Invalid low at index ${i}`, 'candles.low');
    28→    }
    29→    if (typeof c.close !== 'number' || !isFinite(c.close) || c.close <= 0) {
    30→      throw new ValidationError(`Invalid close at index ${i}`, 'candles.close');
    31→    }
    32→    if (c.high < c.low) {
    33→      throw new ValidationError(`High < Low at index ${i}`, 'candles.high');
    34→    }
    35→    if (c.high < c.open || c.high < c.close) {
    36→      throw new ValidationError(`High must be >= open and close at index ${i}`, 'candles.high');
    37→    }
    38→    if (c.low > c.open || c.low > c.close) {
    39→      throw new ValidationError(`Low must be <= open and close at index ${i}`, 'candles.low');
    40→    }
    41→
    42→    // Check ascending timestamps
    43→    if (i > 0) {
    44→      const prev = candles[i - 1]!;
    45→      if (c.timestamp <= prev.timestamp) {
    46→        throw new ValidationError(`Timestamps not ascending at index ${i}`, 'candles.timestamp');
    47→      }
    48→    }
    49→  }
    50→}
    51→
    52→/** Validate an instrument configuration */
    53→export function validateInstrument(config: InstrumentConfig): void {
    54→  if (!config.symbol || typeof config.symbol !== 'string') {
    55→    throw new ConfigurationError('Symbol must be a non-empty string', 'symbol');
    56→  }
    57→  if (config.maxSLPoints <= 0) {
    58→    throw new ConfigurationError('maxSLPoints must be positive', 'maxSLPoints');
    59→  }
    60→  if (config.pointValue <= 0) {
    61→    throw new ConfigurationError('pointValue must be positive', 'pointValue');
    62→  }
    63→  if (config.minFVGSize <= 0) {
    64→    throw new ConfigurationError('minFVGSize must be positive', 'minFVGSize');
    65→  }
    66→  if (config.spread < 0) {
    67→    throw new ConfigurationError('spread must be non-negative', 'spread');
    68→  }
    69→}
    70→
    71→/** Validate risk configuration */
    72→export function validateRiskConfig(config: RiskConfig): void {
    73→  if (config.maxRiskPerTrade <= 0 || config.maxRiskPerTrade > 0.05) {
    74→    throw new ConfigurationError(
    75→      'maxRiskPerTrade must be between 0 and 5%',
    76→      'maxRiskPerTrade',
    77→    );
    78→  }
    79→  if (config.maxDailyDrawdown <= 0 || config.maxDailyDrawdown > 0.1) {
    80→    throw new ConfigurationError(
    81→      'maxDailyDrawdown must be between 0 and 10%',
    82→      'maxDailyDrawdown',
    83→    );
    84→  }
    85→  if (config.maxConsecutiveLosses < 1) {
    86→    throw new ConfigurationError(
    87→      'maxConsecutiveLosses must be >= 1',
    88→      'maxConsecutiveLosses',
    89→    );
    90→  }
    91→  if (config.maxTradesPerDay < 1) {
    92→    throw new ConfigurationError(
    93→      'maxTradesPerDay must be >= 1',
    94→      'maxTradesPerDay',
    95→    );
    96→  }
    97→}
    98→
    99→/**
   100→ * Build a complete AnalysisConfig from a symbol string and optional overrides.
   101→ * Uses INSTRUMENTS lookup and DEFAULT_RISK as base.
   102→ */
   103→export function buildAnalysisConfig(
   104→  symbol: string,
   105→  capital: number,
   106→  riskOverrides?: Partial<RiskConfig>,
   107→  swingLookback?: number,
   108→): AnalysisConfig {
   109→  const instrument = INSTRUMENTS[symbol];
   110→  if (!instrument) {
   111→    throw new ConfigurationError(`Unknown instrument: ${symbol}`, 'symbol');
   112→  }
   113→  if (capital <= 0) {
   114→    throw new ConfigurationError('Capital must be positive', 'capital');
   115→  }
   116→
   117→  const risk: RiskConfig = {
   118→    ...DEFAULT_RISK,
   119→    ...riskOverrides,
   120→  };
   121→  validateInstrument(instrument);
   122→  validateRiskConfig(risk);
   123→
   124→  return {
   125→    instrument,
   126→    risk,
   127→    capital,
   128→    swingLookback: swingLookback ?? 5,
   129→  };
   130→}
